from datetime import datetime, timezone
import pandas as pd
from pathlib import Path

def calcular_otif(df: pd.DataFrame, fecha: str) -> dict:
    if df.empty:
        return {'fecha': fecha, 'otif': 0.0, 'total': 0}

    total = len(df)
    if total == 0:
        return {'fecha': fecha, 'otif': 0.0, 'total': 0}

    a_tiempo = df[df['cumple_fecha'] == True].shape[0]
    otif = round(a_tiempo / total * 100, 2)

    return {
        'fecha': fecha,
        'otif': otif,
        'total': total,
        'timestamp_utc': datetime.now(timezone.utc).isoformat()
    }
